instruction:
`async` makes a function return a Promise.
`await` pauses execution until a Promise resolves — but only inside an `async` function.

Compare the Promise chain from Chapter 17 with the async/await version:

```js
// Promise chain:  fetchUser().then(u => u.name).then(console.log)
// async/await:    const user = await fetchUser(); console.log(user.name);
```

Run both versions — they do the same thing.

starter:
function delay(ms, value) {
  return new Promise(resolve => setTimeout(() => resolve(value), ms));
}

// Promise chain version:
delay(50, { name: "alex", score: 78 })
  .then(u => u.name)
  .then(n => n.toUpperCase())
  .then(console.log);

// async/await version — same logic:
async function main() {
  const user  = await delay(50, { name: "alex", score: 78 });
  const name  = user.name;
  const upper = name.toUpperCase();
  console.log(upper);
}
main();

async function fetchData() {
  console.log("2: fetchData started");
  await new Promise(r => setTimeout(r, 100));
  console.log("4: fetchData done");
  return "result!";
}

console.log("1: Before calling fetchData");
const promise = fetchData();  // starts the async function
console.log("3: After calling fetchData (still waiting)");

promise.then(r => console.log("5: Got:", r));

function fakeRequest(name, shouldFail = false) {
  return new Promise((res, rej) =>
    setTimeout(() => shouldFail ? rej(new Error(`${name} failed!`)) : res(`${name} ok`), 50)
  );
}

async function loadPage() {
  try {
    const user    = await fakeRequest("user");
    const orders  = await fakeRequest("orders", true); // fails!
    const reviews = await fakeRequest("reviews");      // never runs
    return { user, orders, reviews };
  } catch (error) {
    console.log("Caught:", error.message);
    return null;
  }
}

loadPage().then(r => console.log("Result:", r));

function fetchItem(name, ms) {
  return new Promise(r => setTimeout(() => r(`${name} loaded`), ms));
}

async function sequential() {
  const start = Date.now();
  const a = await fetchItem("users",    100);
  const b = await fetchItem("products", 100);
  const c = await fetchItem("orders",   100);
  console.log(`Sequential: ${Date.now() - start}ms`);
  return [a, b, c];
}

async function parallel() {
  const start = Date.now();
  const [a, b, c] = await Promise.all([
    fetchItem("users",    100),
    fetchItem("products", 100),
    fetchItem("orders",   100),
  ]);
  console.log(`Parallel: ${Date.now() - start}ms`);
  return [a, b, c];
}

sequential().then(() => parallel());

async function getScore() {
  return 95; // wrapped in Promise.resolve(95) automatically
}

async function getUser() {
  return { name: "Alex", score: await getScore() };
}

// async functions always return Promises:
console.log(getScore() instanceof Promise); // true

// Use await or .then() to get the value:
getScore().then(s => console.log("Score:", s));

async function main() {
  const score = await getScore();
  const user  = await getUser();
  console.log("Direct:", score);
  console.log("User:",  user.name, user.score);
}
main();

async function* generateNumbers(max) {
  for (let i = 1; i <= max; i++) {
    await new Promise(r => setTimeout(r, 10)); // simulate delay
    yield i;
  }
}

async function main() {
  let sum = 0;
  for await (const num of generateNumbers(5)) {
    console.log(`Got: ${num}`);
    sum += num;
  }
  console.log(`Sum: ${sum}`);
}

main();

async function step1() { throw new Error("Step 1 failed"); }
async function step2() { return await step1(); }
async function step3() { return await step2(); }

// Without handling:
step3().catch(e => console.log("Unhandled:", e.message));

// With try/catch at the top level:
async function main() {
  try {
    await step3();
  } catch (e) {
    console.log("Caught at main:", e.message);
  }
}
main();
